import { useState } from "react";

export default function TodoApp() {
  const [text, setText] = useState("");
  const [todos, setTodos] = useState([]);

  function addTodo() {
    if (!text) return;

    setTodos([
      ...todos,
      {
        text,
        done: false,
      },
    ]);

    setText("");
  }

  function toggleTodo(index) {
    setTodos(
      todos.map((todo, i) =>
        i === index
          ? { ...todo, done: !todo.done }
          : todo
      )
    );
  }

  function deleteTodo(index) {
    setTodos(
      todos.filter((_, i) => i !== index)
    );
  }

  return (
    <main>
      <h1>📝 Todo</h1>

      <input
        value={text}
        onChange={e => setText(e.target.value)}
        placeholder="Task"
      />

      <button onClick={addTodo}>
        Add
      </button>

      <ul>
        {todos.map((todo, i) => (
          <li key={i}>
            <input
              type="checkbox"
              checked={todo.done}
              onChange={() => toggleTodo(i)}
            />

            {todo.done
              ? <s>{todo.text}</s>
              : todo.text}

            <button onClick={() => deleteTodo(i)}>
              Delete
            </button>
          </li>
        ))}
      </ul>
    </main>
  );
}
